import{c as e,Q as a,j as l,m as n}from"./chunks/framework.CQqJojvj.js";const x=JSON.parse('{"title":"14 - 分库分表","description":"","frontmatter":{},"headers":[],"relativePath":"bagu/14-sharding.md","filePath":"bagu/14-sharding.md","lastUpdated":null}'),s={name:"bagu/14-sharding.md"};function r(d,t,i,o,h,g){return a(),l("div",null,[...t[0]||(t[0]=[n(`<h1 id="_14-分库分表" tabindex="-1">14 - 分库分表 <a class="header-anchor" href="#_14-分库分表" aria-label="Permalink to &quot;14 - 分库分表&quot;">​</a></h1><blockquote><p>当单表数据量达到千万级，MySQL 的性能会明显下降。分库分表是大型系统的标配方案。</p></blockquote><hr><h2 id="_1-什么时候需要分库分表" tabindex="-1">1. 什么时候需要分库分表？ <a class="header-anchor" href="#_1-什么时候需要分库分表" aria-label="Permalink to &quot;1. 什么时候需要分库分表？&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">问题</th><th style="text-align:left;">表现</th><th style="text-align:left;">解决方案</th></tr></thead><tbody><tr><td style="text-align:left;">单表数据量大（&gt; 2000w）</td><td style="text-align:left;">慢查询、索引大、重建慢</td><td style="text-align:left;">水平分表</td></tr><tr><td style="text-align:left;">单库连接数高/并发高</td><td style="text-align:left;">数据库 CPU 高、连接池耗尽</td><td style="text-align:left;">垂直分库</td></tr><tr><td style="text-align:left;">写吞吐量瓶颈</td><td style="text-align:left;">写入 TPS 达到上限</td><td style="text-align:left;">水平分库分表</td></tr><tr><td style="text-align:left;">存储容量不足</td><td style="text-align:left;">磁盘接近极限</td><td style="text-align:left;">分库（分散到多台）</td></tr></tbody></table><p><strong>优先考虑优化而非分库：</strong> 索引优化、SQL 优化、读写分离、缓存、数据归档。这些手段都用完还不够才考虑分库分表。</p><hr><h2 id="_2-垂直分库-vs-水平分库" tabindex="-1">2. 垂直分库 vs 水平分库 <a class="header-anchor" href="#_2-垂直分库-vs-水平分库" aria-label="Permalink to &quot;2. 垂直分库 vs 水平分库&quot;">​</a></h2><h3 id="垂直分库" tabindex="-1">垂直分库 <a class="header-anchor" href="#垂直分库" aria-label="Permalink to &quot;垂直分库&quot;">​</a></h3><p>按业务模块拆分不同库：用户库、订单库、商品库。</p><p><strong>优点：</strong> 业务边界清晰，独立扩容。 <strong>缺点：</strong> 跨库 JOIN 无法使用，分布式事务。</p><h3 id="水平分库分表" tabindex="-1">水平分库分表 <a class="header-anchor" href="#水平分库分表" aria-label="Permalink to &quot;水平分库分表&quot;">​</a></h3><p>将同一张表的数据按一定规则拆分到多个库/表中。</p><p><strong>优点：</strong> 单表数据量下降，写入吞吐量提升。 <strong>缺点：</strong> 查询复杂，需要路由层。</p><hr><h2 id="_3-分片策略" tabindex="-1">3. 分片策略 <a class="header-anchor" href="#_3-分片策略" aria-label="Permalink to &quot;3. 分片策略&quot;">​</a></h2><h3 id="分片键选择原则" tabindex="-1">分片键选择原则 <a class="header-anchor" href="#分片键选择原则" aria-label="Permalink to &quot;分片键选择原则&quot;">​</a></h3><ol><li><strong>高区分度</strong> — 数据能均匀分散到各分片（避免热点）</li><li><strong>查询命中</strong> — 大部分查询能带上分片键</li><li><strong>避免跨分片</strong> — 减少分布式 JOIN / 跨分片聚合</li></ol><h3 id="常用分片算法" tabindex="-1">常用分片算法 <a class="header-anchor" href="#常用分片算法" aria-label="Permalink to &quot;常用分片算法&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">算法</th><th style="text-align:left;">示例</th><th style="text-align:left;">优点</th><th style="text-align:left;">缺点</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>取模</strong></td><td style="text-align:left;"><code>hash(key) % N</code></td><td style="text-align:left;">数据分布均匀</td><td style="text-align:left;">扩容时需要全量迁移</td></tr><tr><td style="text-align:left;"><strong>范围分片</strong></td><td style="text-align:left;"><code>order_id ∈ [1, 1000w] → 分片1</code></td><td style="text-align:left;">扩容方便</td><td style="text-align:left;">热点数据集中（最新数据在同一分片）</td></tr><tr><td style="text-align:left;"><strong>一致性哈希</strong></td><td style="text-align:left;">虚拟节点映射到哈希环</td><td style="text-align:left;">扩容迁移量小</td><td style="text-align:left;">实现复杂</td></tr><tr><td style="text-align:left;"><strong>复合分片</strong></td><td style="text-align:left;">先范围再取模</td><td style="text-align:left;">灵活</td><td style="text-align:left;">复杂</td></tr></tbody></table><hr><h2 id="_4-分库分表后的挑战" tabindex="-1">4. 分库分表后的挑战 <a class="header-anchor" href="#_4-分库分表后的挑战" aria-label="Permalink to &quot;4. 分库分表后的挑战&quot;">​</a></h2><h3 id="分布式主键" tabindex="-1">分布式主键 <a class="header-anchor" href="#分布式主键" aria-label="Permalink to &quot;分布式主键&quot;">​</a></h3><p>雪花算法生成全局唯一 ID（趋势递增，保证 MyISAM/InnoDB 写入性能）。</p><h3 id="跨分片查询" tabindex="-1">跨分片查询 <a class="header-anchor" href="#跨分片查询" aria-label="Permalink to &quot;跨分片查询&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">场景</th><th style="text-align:left;">解决方案</th></tr></thead><tbody><tr><td style="text-align:left;">按非分片键查询</td><td style="text-align:left;">ES 索引（先查 ES 拿到分片键，再查 DB）+ MySQL 异构索引表</td></tr><tr><td style="text-align:left;">跨分片分页</td><td style="text-align:left;">全局查询（每个分片取前 N 条，汇总再排序）→ 性能优化：使用 ES</td></tr><tr><td style="text-align:left;">跨分片 JOIN</td><td style="text-align:left;">应用层 JOIN / 字段冗余 / 全局表</td></tr><tr><td style="text-align:left;">跨分片聚合（count/sum/avg）</td><td style="text-align:left;">各分片执行 → 应用层汇总（或使用数据仓库如 ClickHouse）</td></tr></tbody></table><h3 id="分布式事务" tabindex="-1">分布式事务 <a class="header-anchor" href="#分布式事务" aria-label="Permalink to &quot;分布式事务&quot;">​</a></h3><p>使用最终一致性方案（本地消息表 / RocketMQ 事务消息 / Seata Saga 模式）。</p><h3 id="扩容与数据迁移" tabindex="-1">扩容与数据迁移 <a class="header-anchor" href="#扩容与数据迁移" aria-label="Permalink to &quot;扩容与数据迁移&quot;">​</a></h3><p><strong>方案一：翻倍扩容（推荐）</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>分片 N → 分片 2N</span></span>
<span class="line"><span>迁移：hash(key) % N 中一半的数据迁移到新分片</span></span>
<span class="line"><span>迁移量：50%</span></span>
<span class="line"><span></span></span>
<span class="line"><span>例：2 分片 → 4 分片</span></span>
<span class="line"><span>  原来 hash%2=0 的数据，一半(hash%4=0)留在原分片，一半(hash%4=2)迁移</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p><strong>方案二：一致性哈希</strong></p><p>迁移量：约 1/N。</p><p><strong>数据迁移流程：</strong></p><ol><li>双写（新旧表都写）+ 异步数据迁移</li><li>数据校验（行数、关键数据抽样对比）</li><li>灰度切换读流量</li><li>停止写旧表</li></ol><hr><h2 id="_5-常用中间件" tabindex="-1">5. 常用中间件 <a class="header-anchor" href="#_5-常用中间件" aria-label="Permalink to &quot;5. 常用中间件&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">方案</th><th style="text-align:left;">说明</th><th style="text-align:left;">适用场景</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>ShardingSphere-JDBC</strong></td><td style="text-align:left;">客户端分片，嵌入应用</td><td style="text-align:left;">自研项目、灵活性高</td></tr><tr><td style="text-align:left;"><strong>ShardingSphere-Proxy</strong></td><td style="text-align:left;">透明代理，独立部署</td><td style="text-align:left;">多语言、对应用透明</td></tr><tr><td style="text-align:left;"><strong>Vitess</strong></td><td style="text-align:left;">YouTube 开源，基于 MySQL</td><td style="text-align:left;">大规模场景</td></tr><tr><td style="text-align:left;"><strong>MyCat</strong></td><td style="text-align:left;">国内开源中间件</td><td style="text-align:left;">传统企业</td></tr></tbody></table><hr><h2 id="_6-什么时候不该分库分表" tabindex="-1">6. 什么时候不该分库分表 <a class="header-anchor" href="#_6-什么时候不该分库分表" aria-label="Permalink to &quot;6. 什么时候不该分库分表&quot;">​</a></h2><ol><li>数据量不超过千万</li><li>单表 QPS 远低于数据库承载上限</li><li>业务逻辑非常复杂（关联查询极多）</li><li>团队规模小（分库分表引入的运维成本远超性能收益）</li></ol><p>先尝试：<strong>优化索引 → 读写分离 → 缓存 → 冷热数据分离 → 数据归档 → 最后才分库分表</strong>。</p>`,42)])])}const f=e(s,[["render",r]]);export{x as __pageData,f as default};
